import{_ as e,O as i,H as o,f as r,k as d,i as l}from"./chunks/framework.Pt2pSV98.js";const m=JSON.parse('{"title":"Midjourney","description":"AI 图像生成标杆——Discord 上使用，艺术风格极强，是设计师和创作者的挚爱","frontmatter":{"title":"Midjourney","description":"AI 图像生成标杆——Discord 上使用，艺术风格极强，是设计师和创作者的挚爱","difficulty":"beginner"},"headers":[],"relativePath":"tools/midjourney.md","filePath":"tools/midjourney.md"}'),n={name:"tools/midjourney.md"};function s(h,t,u,c,p,b){const a=i("DifficultyBadge");return o(),r("div",null,[d(a,{level:"beginner"}),t[0]||(t[0]=l('<h1 id="midjourney" tabindex="-1">Midjourney <a class="header-anchor" href="#midjourney" aria-label="Permalink to &quot;Midjourney&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>AI 图像生成的标杆</strong>——从概念艺术到照片级写实，Midjourney 的画面质感和艺术造诣是行业天花板。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>Midjourney</td></tr><tr><td>价格</td><td>Basic $10/月 / Standard $30/月 / Pro $60/月</td></tr><tr><td>平台</td><td>Discord + 网页版</td></tr><tr><td>首发时间</td><td>2022 年 7 月（公测）</td></tr><tr><td>特色</td><td>艺术风格极强、美学质感佳、V7 模型画质飞跃</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🎨-文生图" tabindex="-1">🎨 文生图 <a class="header-anchor" href="#🎨-文生图" aria-label="Permalink to &quot;🎨 文生图&quot;">​</a></h3><p>在 Discord 中输入 <code>/imagine</code> 命令，加上你的描述（Prompt），Midjourney 会生成 4 张图像供你选择。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/imagine prompt: a futuristic city at sunset, cyberpunk style, neon lights, cinematic lighting --ar 16:9</span></span></code></pre></div><h3 id="🔄-变体与精修" tabindex="-1">🔄 变体与精修 <a class="header-anchor" href="#🔄-变体与精修" aria-label="Permalink to &quot;🔄 变体与精修&quot;">​</a></h3><p>生成后可以：</p><ul><li><strong>U1-U4</strong>：放大（Upscale）选中的图片，获得更高质量版本</li><li><strong>V1-V4</strong>：基于选中图片创建变体</li><li><strong>Remix</strong>：修改 Prompt 后生成新变体</li></ul><h3 id="🖼️-图生图" tabindex="-1">🖼️ 图生图 <a class="header-anchor" href="#🖼️-图生图" aria-label="Permalink to &quot;🖼️ 图生图&quot;">​</a></h3><p>上传一张参考图，Midjourney 参考其构图、风格生成新图像。</p><h3 id="📐-参数控制" tabindex="-1">📐 参数控制 <a class="header-anchor" href="#📐-参数控制" aria-label="Permalink to &quot;📐 参数控制&quot;">​</a></h3><p>大量参数可以精细控制生成效果：</p><ul><li><code>--ar 16:9</code>：宽高比</li><li><code>--stylize 100</code>：艺术化程度（0-1000）</li><li><code>--chaos 50</code>：创意随机度（0-100）</li><li><code>--no text</code>：排除某些元素</li></ul><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>艺术感最强</strong>：画面的光影、构图、配色远超同类产品</li><li><strong>风格多样</strong>：从超写实到抽象艺术都能驾驭</li><li><strong>社区强大</strong>：Discord 社区里有海量 Prompt 和成果分享</li><li><strong>迭代迅速</strong>：模型版本更新快，V7 画质和指令遵循能力显著提升</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li><strong>需付费</strong>：没有免费版（除了偶尔的免费试用）</li><li><strong>Discord 依赖</strong>：传统上必须在 Discord 上使用，网页版功能有限</li><li><strong>理解偏差</strong>：对复杂 Prompt 的理解不如 DALL·E</li><li><strong>无法精确控制</strong>：生成结果有一定随机性，不太适合需要精确还原的场景</li><li><strong>不支持直接编辑</strong>：不能像 Photoshop 那样进行像素级编辑</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 设计师、插画师、概念艺术家</li><li>✅ 需要高质量视觉素材的内容创作者</li><li>✅ 追求画面美感的用户</li><li>✅ 愿意付费的用户</li><li>⚠️ 需要免费工具 → 选 Stable Diffusion</li><li>⚠️ 需要精确控制 → 选 Stable Diffusion + ControlNet</li></ul><h2 id="midjourney-vs-dall·e-vs-stable-diffusion" tabindex="-1">Midjourney vs DALL·E vs Stable Diffusion <a class="header-anchor" href="#midjourney-vs-dall·e-vs-stable-diffusion" aria-label="Permalink to &quot;Midjourney vs DALL·E vs Stable Diffusion&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Midjourney</th><th>DALL·E</th><th>Stable Diffusion</th></tr></thead><tbody><tr><td>画面美感</td><td>⭐⭐⭐</td><td>⭐⭐</td><td>⭐⭐</td></tr><tr><td>理解 Prompt</td><td>⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐</td></tr><tr><td>可控性</td><td>⭐⭐</td><td>⭐⭐</td><td>⭐⭐⭐</td></tr><tr><td>价格</td><td>⭐ ($10+/月)</td><td>⭐⭐ ($0.04/张)</td><td>⭐⭐⭐ (免费)</td></tr><tr><td>上手难度</td><td>⭐⭐⭐ (简单)</td><td>⭐⭐⭐ (极简)</td><td>⭐ (需配置)</td></tr></tbody></table><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/dalle.html">DALL·E</a> —— OpenAI 的图像生成工具</li><li><a href="/ai-knowledge/tools/stable-diffusion.html">Stable Diffusion</a> —— 开源图像生成</li><li><a href="/ai-knowledge/prompts/principles.html">清晰的 Prompt 怎么写</a> —— 好的 Prompt 出好图</li></ul><hr><blockquote><p>最后更新：2026.05</p></blockquote>',29))])}const g=e(n,[["render",s]]);export{m as __pageData,g as default};
